/* dataset.h — UCI-HAR data interface for on-device training
 *
 * Two modes:
 *   1. UART streaming (primary): host PC sends samples during training.
 *      Protocol: [1-byte label] [INPUT_T*INPUT_C floats, little-endian IEEE-754]
 *      Pico responds: [float loss] [float train_acc]
 *
 *   2. Embedded test set (fallback): a small fixed set compiled into flash
 *      for stand-alone accuracy evaluation. Generated by tools/prepare_data.py.
 *
 * Class index mapping:
 *   0 WALKING  1 WALKING_UPSTAIRS  2 WALKING_DOWNSTAIRS
 *   3 SITTING  4 STANDING          5 LAYING
 */

#ifndef DATASET_H
#define DATASET_H

#include <stdint.h>
#include "config.h"

/* ── UART streaming ───────────────────────────────────────────────── */

/* Read one sample from UART.
 *   sample_out : float[INPUT_T * INPUT_C]  (pre-allocated by caller)
 *   label_out  : 0-5
 * Returns 1 on success, 0 on timeout / framing error.
 */
int dataset_uart_recv(float *sample_out, int *label_out);

/* Send training feedback to host.
 *   step  : global training step
 *   loss  : current batch loss
 *   acc   : running training accuracy (0-1)
 */
void dataset_uart_send(int step, float loss, float acc);

/* ── Embedded test set ────────────────────────────────────────────── */

/* Number of embedded test samples (defined in dataset.c).
 * Set by tools/prepare_data.py; 0 if no embedded data available.   */
extern const int DATASET_TEST_N;

/* Pointer to embedded test data arrays (read-only, in flash).
 * Shape: [DATASET_TEST_N][INPUT_T * INPUT_C]
 * Values are already normalised to [-1, 1].                         */
extern const float DATASET_TEST_X[][INPUT_T * INPUT_C];

/* Pointer to embedded test labels (0-5). */
extern const uint8_t DATASET_TEST_Y[];

/* ── Normalisation ────────────────────────────────────────────────── */

/* Normalise a raw UCI-HAR sample in-place to approximately [-1, 1].
 * UCI-HAR accelerometer data range is roughly [-1, 1] g already,
 * but raw sensor data may need z-score normalisation.
 *
 * Per-channel mean and std are from the UCI-HAR training split
 * (pre-computed by tools/prepare_data.py and hardcoded here).
 */
void dataset_normalize(float *sample);

/* Class name string for pretty-printing. */
const char *dataset_class_name(int label);

/* ── PC file-based loading (non-Pico builds only) ────────────────── */
#ifndef PICO_BUILD

/* Dataset handle for PC mode. */
typedef struct {
    float   *X;       /* [N][INPUT_T * INPUT_C] — all samples        */
    uint8_t *y;       /* [N]                    — labels 0-5         */
    int      N;       /* total samples                                */
    int      cursor;  /* current position (for sequential iteration)  */
} PC_Dataset;

/* Load one split from the pre-processed .npy data directory.
 *   data_dir : path to folder containing {split}_x.npy / {split}_y.npy
 *              Produced by: python examples/har_classifier/prepare_data.py
 *              Default location: OnDeviceTraining/examples/har_classifier/data
 *   split    : "train", "val", or "test"
 *
 * X.npy shape [N,9,128] is transposed to [N,128,9] on load.
 * Allocates X and y internally — call pc_dataset_free() when done.
 * Returns 1 on success, 0 on error.                                  */
int pc_dataset_load(PC_Dataset *ds, const char *data_dir,
                    const char *split);

/* Free memory allocated by pc_dataset_load(). */
void pc_dataset_free(PC_Dataset *ds);

/* Get next sample (wraps around). Normalises in-place.
 *   sample_out : float[INPUT_T * INPUT_C]
 *   label_out  : 0-5
 */
void pc_dataset_next(PC_Dataset *ds, float *sample_out, int *label_out);

/* Shuffle dataset order (Fisher-Yates). */
void pc_dataset_shuffle(PC_Dataset *ds);

#endif /* !PICO_BUILD */

#endif /* DATASET_H */
